#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

int64_t powmod(int64_t base, int64_t exponent, int64_t mod) {
    int64_t result = 1;
    while (exponent > 0) {
        if (exponent & 1) result = (result * base) % mod;
        base = (base * base) % mod;
        exponent >>= 1;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int64_t V, N;
        scanf("%lld %lld", &V, &N);
        int64_t P[2], Q[2], A0, B0, C0, M0, A1, B1, C1, M1;
        scanf("%lld %lld %lld %lld %lld %lld", &P[0], &P[1], &A0, &B0, &C0, &M0);
        scanf("%lld %lld %lld %lld %lld %lld", &Q[0], &Q[1], &A1, &B1, &C1, &M1);
        int64_t L[N];
        for (int i = 0; i < N; i++) {
            if (i >= 2) {
                P[i % 2] = (A0 * A0 * P[(i - 1) % 2] + B0 * P[(i - 2) % 2] + C0) % M0;
                Q[i % 2] = (A1 * A1 * Q[(i - 1) % 2] + B1 * Q[(i - 2) % 2] + C1) % M1;
            }
            L[i] = P[i % 2] * M1 + Q[i % 2] + 1;
        }
        int64_t result = 1;
        for (int i = 0; i < N; i++) {
            result = (result * powmod(V, L[i] - 1, MOD)) % MOD;
        }
        printf("%lld\n", result);
    }
    return 0;
}

