import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.StringTokenizer;

public class Main {
    static final long MOD = 1000000007;

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long V = Long.parseLong(st.nextToken());
            long N = Long.parseLong(st.nextToken());
            st = new StringTokenizer(br.readLine());
            long P[] = new long[2];
            long Q[] = new long[2];
            long A0 = Long.parseLong(st.nextToken());
            long B0 = Long.parseLong(st.nextToken());
            long C0 = Long.parseLong(st.nextToken());
            long M0 = Long.parseLong(st.nextToken());
            P[0] = Long.parseLong(st.nextToken());
            P[1] = Long.parseLong(st.nextToken());
            st = new StringTokenizer(br.readLine());
            Q[0] = Long.parseLong(st.nextToken());
            Q[1] = Long.parseLong(st.nextToken());
            long A1 = Long.parseLong(st.nextToken());
            long B1 = Long.parseLong(st.nextToken());
            long C1 = Long.parseLong(st.nextToken());
            long M1 = Long.parseLong(st.nextToken());
            long L[] = new long[(int)N];
            for (int i = 0; i < N; i++) {
                if (i >= 2) {
                    P[i % 2] = (A0 * A0 * P[(i - 1) % 2] + B0 * P[(i - 2) % 2] + C0) % M0;
                    Q[i % 2] = (A1 * A1 * Q[(i - 1) % 2] + B1 * Q[(i - 2) % 2] + C1) % M1;
                }
                L[i] = P[i % 2] * M1 + Q[i % 2] + 1;
            }
            long result = 1;
            for (int i = 0; i < N; i++) {
                result = (result * powmod(V, L[i] - 1, MOD)) % MOD;
            }
            pw.println(result);
        }
        pw.close();
    }

    static long powmod(long base, long exponent, long mod) {
        long result = 1;
        while (exponent > 0) {
            if (exponent % 2 == 1) result = (result * base) % mod;
            base = (base * base) % mod;
            exponent >>= 1;
        }
        return result;
    }
}

